#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e6+5;
int n,m,a[MAXN],v[MAXN],cnt,l[MAXN],r[MAXN],vis[MAXN]; 
struct node
{
    int x,id;
    bool operator < (const node&a) const
	{
        return abs(a.x)<abs(x);
    }
};
priority_queue<node> q;
signed main(void)
{
    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n>>m;
	FOR(i,1,n)
	{
		cin>>a[i];
        if(!a[i])--i,--n;
	}
	v[++cnt]=a[1];
	FOR(i,2,n)
	{
		bool x=v[cnt]<0,y=a[i]<0;
        if(x==y)
		{
			v[cnt]+=a[i];
		}
        else
		{
			v[++cnt]=a[i];
		}
	} 
    int x=0,ans=0;
    FOR(i,1,cnt)
    {
        if(v[i]>0)
		{
			++x;
			ans+=v[i];
		}
        q.push({v[i],i});
		r[i]=i+1;
		l[i]=i-1;
    }
    v[0]=v[cnt+1]=llinf;
    r[0]=1,l[cnt+1]=cnt;
	r[cnt+1]=cnt+1;
    while(x>m)
    {
        int front=q.top().id;
        q.pop();
        if(vis[front]||((l[front]==0||r[front]>cnt)&&v[front]<0))
		{
			continue;
		}
        ans-=abs(v[front]);
        v[front]+=v[l[front]]+v[r[front]];
        q.push(node{v[front],front});
        vis[l[front]]=vis[r[front]]=true;
        l[front]=l[l[front]];
		r[l[front]]=front;
        r[front]=r[r[front]];
		l[r[front]]=front;
        --x;
    }
    cout<<max(0ll,ans);
    return false;
}
